import os
import json
import pymysql
from flask import jsonify

# Connection configuration from environment variables
DB_USER = os.environ.get('DB_USER')
DB_PASS = os.environ.get('DB_PASS')
DB_NAME = os.environ.get('DB_NAME')
DB_HOST = os.environ.get('DB_HOST')  # Private IP or Cloud SQL Proxy address
DB_PORT = int(os.environ.get('DB_PORT', 3306))
CLOUD_SQL_CONNECTION_NAME = os.environ.get('CLOUD_SQL_CONNECTION_NAME')

# Whitelist of allowed table names and column names to prevent injection
ALLOWED_TABLES = {
    'products': ['id', 'name', 'category', 'price', 'description', 'status', 'created_at'],
    'customers': ['id', 'first_name', 'last_name', 'email', 'city', 'state', 'country', 'created_at'],
    'orders': ['id', 'customer_id', 'product_id', 'quantity', 'total', 'status', 'order_date'],
}

ALLOWED_OPERATORS = {
    'eq': '=',
    'neq': '!=',
    'gt': '>',
    'gte': '>=',
    'lt': '<',
    'lte': '<=',
    'like': 'LIKE',
    'in': 'IN',
}

ALLOWED_SORT_DIRECTIONS = {'asc', 'desc'}

MAX_LIMIT = 500
DEFAULT_LIMIT = 50


def get_connection():
    """Create a database connection using Cloud SQL socket or TCP."""
    if CLOUD_SQL_CONNECTION_NAME:
        # Connect via Unix socket (for Cloud Functions with Cloud SQL connector)
        unix_socket = f'/cloudsql/{CLOUD_SQL_CONNECTION_NAME}'
        return pymysql.connect(
            user=DB_USER,
            password=DB_PASS,
            db=DB_NAME,
            unix_socket=unix_socket,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=10,
            read_timeout=30,
        )
    else:
        # Connect via TCP (for local development / Cloud SQL Proxy)
        return pymysql.connect(
            host=DB_HOST,
            port=DB_PORT,
            user=DB_USER,
            password=DB_PASS,
            db=DB_NAME,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=10,
            read_timeout=30,
        )


def validate_table(table_name):
    """Validate table name against whitelist."""
    if table_name not in ALLOWED_TABLES:
        raise ValueError(
            f"Invalid table: '{table_name}'. Allowed tables: {list(ALLOWED_TABLES.keys())}"
        )
    return table_name


def validate_column(table_name, column_name):
    """Validate column name against whitelist for the given table."""
    allowed_columns = ALLOWED_TABLES.get(table_name, [])
    if column_name not in allowed_columns:
        raise ValueError(
            f"Invalid column: '{column_name}' for table '{table_name}'. "
            f"Allowed columns: {allowed_columns}"
        )
    return column_name


def validate_operator(op):
    """Validate operator against whitelist."""
    if op not in ALLOWED_OPERATORS:
        raise ValueError(
            f"Invalid operator: '{op}'. Allowed operators: {list(ALLOWED_OPERATORS.keys())}"
        )
    return ALLOWED_OPERATORS[op]


def build_search_query(table, filters=None, select_columns=None, sort_by=None,
                       sort_dir='asc', limit=DEFAULT_LIMIT, offset=0):
    """
    Build a parameterized SQL query dynamically from validated inputs.

    Returns a tuple of (query_string, params_list).
    All user-supplied VALUES go through parameterized queries (%s placeholders).
    All identifiers (table names, column names) are validated against whitelists.

    --- WHY NOT STRING CONCATENATION? ---
    String concatenation for SQL (e.g., f"SELECT * FROM {table} WHERE name = '{user_input}'")
    is the #1 cause of SQL injection attacks. An attacker could send:
        name = "'; DROP TABLE products; --"
    and destroy your database.

    Parameterized queries send the query structure and values SEPARATELY to the database,
    making injection impossible for values. For identifiers (table/column names), we use
    strict whitelisting since they can't be parameterized in MySQL.
    """
    params = []

    # Validate and build SELECT clause
    if select_columns:
        validated_cols = []
        for col in select_columns:
            validate_column(table, col)
            validated_cols.append(f"`{col}`")
        select_clause = ', '.join(validated_cols)
    else:
        select_clause = '*'

    # Table name is validated against whitelist (cannot be parameterized)
    validate_table(table)
    query = f"SELECT {select_clause} FROM `{table}`"

    # Build WHERE clause with parameterized values
    if filters:
        where_conditions = []
        for f in filters:
            column = f.get('column')
            operator_key = f.get('operator', 'eq')
            value = f.get('value')

            if column is None or value is None:
                continue

            # Validate column and operator against whitelists
            validate_column(table, column)
            sql_operator = validate_operator(operator_key)

            if operator_key == 'in':
                # Handle IN operator with multiple parameterized placeholders
                if isinstance(value, str):
                    values_list = [v.strip() for v in value.split(',')]
                elif isinstance(value, list):
                    values_list = value
                else:
                    values_list = [value]

                if not values_list:
                    continue

                placeholders = ', '.join(['%s'] * len(values_list))
                where_conditions.append(f"`{column}` IN ({placeholders})")
                params.extend(values_list)

            elif operator_key == 'like':
                # Escape special LIKE characters in user input, then add wildcards
                escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                where_conditions.append(f"`{column}` LIKE %s")
                params.append(f"%{escaped_value}%")

            else:
                # Standard comparison operators - value is parameterized
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(value)

        if where_conditions:
            query += " WHERE " + " AND ".join(where_conditions)

    # Build ORDER BY clause (column validated against whitelist)
    if sort_by:
        validate_column(table, sort_by)
        direction = sort_dir.lower() if sort_dir.lower() in ALLOWED_SORT_DIRECTIONS else 'asc'
        query += f" ORDER BY `{sort_by}` {direction.upper()}"

    # LIMIT and OFFSET are parameterized as integers
    limit = min(int(limit), MAX_LIMIT)
    offset = max(int(offset), 0)
    query += " LIMIT %s OFFSET %s"
    params.extend([limit, offset])

    return query, params


def build_count_query(table, filters=None):
    """Build a parameterized COUNT query for pagination metadata."""
    params = []
    validate_table(table)
    query = f"SELECT COUNT(*) as total FROM `{table}`"

    if filters:
        where_conditions = []
        for f in filters:
            column = f.get('column')
            operator_key = f.get('operator', 'eq')
            value = f.get('value')

            if column is None or value is None:
                continue

            validate_column(table, column)
            sql_operator = validate_operator(operator_key)

            if operator_key == 'in':
                if isinstance(value, str):
                    values_list = [v.strip() for v in value.split(',')]
                elif isinstance(value, list):
                    values_list = value
                else:
                    values_list = [value]
                if not values_list:
                    continue
                placeholders = ', '.join(['%s'] * len(values_list))
                where_conditions.append(f"`{column}` IN ({placeholders})")
                params.extend(values_list)
            elif operator_key == 'like':
                escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                where_conditions.append(f"`{column}` LIKE %s")
                params.append(f"%{escaped_value}%")
            else:
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(value)

        if where_conditions:
            query += " WHERE " + " AND ".join(where_conditions)

    return query, params


def parse_request_params(request):
    """
    Parse HTTP request into structured search parameters.

    Supports both query string params and JSON body.

    Query string example:
        GET /search?table=products&filter.0.column=category&filter.0.operator=eq&filter.0.value=electronics
            &filter.1.column=price&filter.1.operator=lte&filter.1.value=100
            &select=id,name,price&sort_by=price&sort_dir=desc&limit=20&offset=0

    JSON body example:
        POST /search
        {
            "table": "products",
            "filters": [
                {"column": "category", "operator": "eq", "value": "electronics"},
                {"column": "price", "operator": "lte", "value": 100},
                {"column": "name", "operator": "like", "value": "phone"},
                {"column": "status", "operator": "in", "value": ["active", "featured"]}
            ],
            "select": ["id", "name", "price", "category"],
            "sort_by": "price",
            "sort_dir": "desc",
            "limit": 20,
            "offset": 0
        }
    """
    if request.is_json:
        data = request.get_json(silent=True) or {}
        table = data.get('table')
        filters = data.get('filters', [])
        select_columns = data.get('select')
        sort_by = data.get('sort_by')
        sort_dir = data.get('sort_dir', 'asc')
        limit = data.get('limit', DEFAULT_LIMIT)
        offset = data.get('offset', 0)
    else:
        args = request.args
        table = args.get('table')

        # Parse filters from query string: filter.0.column, filter.0.operator, filter.0.value
        filters = []
        i = 0
        while True:
            col = args.get(f'filter.{i}.column')
            if col is None:
                break
            filters.append({
                'column': col,
                'operator': args.get(f'filter.{i}.operator', 'eq'),
                'value': args.get(f'filter.{i}.value', ''),
            })
            i += 1

        select_raw = args.get('select')
        select_columns = [c.strip() for c in select_raw.split(',')] if select_raw else None
        sort_by = args.get('sort_by')
        sort_dir = args.get('sort_dir', 'asc')
        limit = args.get('limit', DEFAULT_LIMIT)
        offset = args.get('offset', 0)

    return {
        'table': table,
        'filters': filters,
        'select_columns': select_columns,
        'sort_by': sort_by,
        'sort_dir': sort_dir,
        'limit': limit,
        'offset': offset,
    }


def search_api(request):
    """
    Cloud Function entry point for the flexible search API.

    Handles CORS, parses request parameters, builds parameterized SQL queries,
    and returns paginated results with metadata.
    """
    # Handle CORS preflight
    if request.method == 'OPTIONS':
        headers = {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Access-Control-Max-Age': '3600',
        }
        return ('', 204, headers)

    cors_headers = {'Access-Control-Allow-Origin': '*'}

    try:
        # Parse and validate request
        params = parse_request_params(request)

        if not params['table']:
            return (
                jsonify({
                    'error': 'Missing required parameter: table',
                    'allowed_tables': list(ALLOWED_TABLES.keys()),
                }),
                400,
                cors_headers,
            )

        # Build parameterized queries (SAFE - no string concatenation of user values)
        search_query, search_params = build_search_query(
            table=params['table'],
            filters=params['filters'],
            select_columns=params['select_columns'],
            sort_by=params['sort_by'],
            sort_dir=params['sort_dir'],
            limit=params['limit'],
            offset=params['offset'],
        )

        count_query, count_params = build_count_query(
            table=params['table'],
            filters=params['filters'],
        )

        # Execute queries
        connection = get_connection()
        try:
            with connection.cursor() as cursor:
                # Get total count for pagination
                cursor.execute(count_query, count_params)
                total_count = cursor.fetchone()['total']

                # Get search results
                cursor.execute(search_query, search_params)
                results = cursor.fetchall()

                # Convert non-serializable types (datetime, Decimal, etc.)
                serialized_results = []
                for row in results:
                    serialized_row = {}
                    for key, value in row.items():
                        if hasattr(value, 'isoformat'):
                            serialized_row[key] = value.isoformat()
                        elif isinstance(value, bytes):
                            serialized_row[key] = value.decode('utf-8', errors='replace')
                        else:
                            serialized_row[key] = value
                    serialized_results.append(serialized_row)

        finally:
            connection.close()

        limit = min(int(params['limit']), MAX_LIMIT)
        offset = max(int(params['offset']), 0)

        response = {
            'success': True,
            'data': serialized_results,
            'pagination': {
                'total': total_count,
                'limit': limit,
                'offset': offset,
                'has_more': (offset + limit) < total_count,
            },
            'query_info': {
                'table': params['table'],
                'filters_applied': len(params['filters']),
                'results_returned': len(serialized_results),
            },
        }

        return (jsonify(response), 200, cors_headers)

    except ValueError as e:
        return (
            jsonify({'success': False, 'error': f'Validation error: {str(e)}'}),
            400,
            cors_headers,
        )
    except pymysql.OperationalError as e:
        error_code = e.args[0] if e.args else 'unknown'
        return (
            jsonify({
                'success': False,
                'error': 'Database connection error',
                'detail': f'MySQL error code: {error_code}',
            }),
            503,
            cors_headers,
        )
    except pymysql.ProgrammingError as e:
        return (
            jsonify({'success': False, 'error': 'Query execution error', 'detail': str(e)}),
            400,
            cors_headers,
        )
    except Exception as e:
        return (
            jsonify({'success': False, 'error': 'Internal server error'}),
            500,
            cors_headers,
        )